#include <stdio.h>

int mergeSort(int arr[], int n, int temp[])
{
    int mid, inv_count = 0;
    if (n < 2)
        return 0;

    mid = n / 2;
    inv_count += mergeSort(arr, mid, temp);
    inv_count += mergeSort(arr + mid, n - mid, temp);

    int i = 0, j = mid, k = 0;
    while (i < mid && j < n)
    {
        if (arr[i] <= arr[j])
        {
            temp[k++] = arr[i++];
        }
        else
        {
            temp[k++] = arr[j++];
            inv_count += (mid - i);
        }
    }

    while (i < mid)
        temp[k++] = arr[i++];
    while (j < n)
        temp[k++] = arr[j++];

    for (i = 0; i < n; i++)
        arr[i] = temp[i];

    return inv_count;
}

int countInversions(int arr[], int n)
{
    int temp[n];
    return mergeSort(arr, n, temp);
}

int main()
{
    int arr[] = {5, 2, 8, 1, 9, 3, 7};
    int n = sizeof(arr) / sizeof(arr[0]);
    printf("Number of inversions are %d\n", countInversions(arr, n));
    return 0;
}

