import java.util.*;

public class Main {
    public static int mergeSort(int[] arr, int n, int[] temp)
    {
        int mid, inv_count = 0;
        if (n < 2)
            return 0;

        mid = n / 2;
        inv_count += mergeSort(arr, mid, temp);
        inv_count += mergeSort(arr, mid, n - mid, temp);

        int i = 0, j = mid, k = 0;
        while (i < mid && j < n)
        {
            if (arr[i] <= arr[j])
            {
                temp[k++] = arr[i++];
            }
            else
            {
                temp[k++] = arr[j++];
                inv_count += (mid - i);
            }
        }

        while (i < mid)
            temp[k++] = arr[i++];
        while (j < n)
            temp[k++] = arr[j++];

        for (i = 0; i < n; i++)
            arr[i] = temp[i];

        return inv_count;
    }

    public static int mergeSort(int[] arr, int start, int end, int[] temp)
    {
        int mid, inv_count = 0;
        if (end - start < 2)
            return 0;

        mid = (start + end) / 2;
        inv_count += mergeSort(arr, start, mid, temp);
        inv_count += mergeSort(arr, mid, end, temp);

        int i = start, j = mid, k = start;
        while (i < mid && j < end)
        {
            if (arr[i] <= arr[j])
            {
                temp[k++] = arr[i++];
            }
            else
            {
                temp[k++] = arr[j++];
                inv_count += (mid - i);
            }
        }

        while (i < mid)
            temp[k++] = arr[i++];
        while (j < end)
            temp[k++] = arr[j++];

        for (i = start; i < end; i++)
            arr[i] = temp[i];

        return inv_count;
    }

    public static int countInversions(int[] arr)
    {
        int[] temp = new int[arr.length];
        return mergeSort(arr, arr.length, temp);
    }

    public static void main(String[] args)
    {
        int[] arr = {5, 2, 8, 1, 9, 3, 7};
        System.out.println("Number of inversions are " + countInversions(arr));
    }
}

