function mergeSort(arr) {
    if (arr.length < 2) {
        return [arr, 0];
    }
    let mid = Math.floor(arr.length / 2);
    let [left, invLeft] = mergeSort(arr.slice(0, mid));
    let [right, invRight] = mergeSort(arr.slice(mid));
    let [merged, invMerge] = merge(left, right);
    return [merged, invLeft + invRight + invMerge];
}

function merge(left, right) {
    let merged = [];
    let invCount = 0;
    let i = 0;
    let j = 0;
    while (i < left.length && j < right.length) {
        if (left[i] <= right[j]) {
            merged.push(left[i]);
            i++;
        } else {
            merged.push(right[j]);
            invCount += left.length - i;
            j++;
        }
    }
    while (i < left.length) {
        merged.push(left[i]);
        i++;
    }
    while (j < right.length) {
        merged.push(right[j]);
        j++;
    }
    return [merged, invCount];
}

function countInversions(arr) {
    let [, invCount] = mergeSort(arr);
    return invCount;
}

